bool test_batch_operations() {
    // 1. Create observer nodes
    auto node1 = std::make_shared<reaction::ObserverNode>();
    auto node2 = std::make_shared<reaction::ObserverNode>();
    auto node3 = std::make_shared<reaction::ObserverNode>();

    // Set unique names for easier identification
    node1->setName("Node1");
    node2->setName("Node2");
    node3->setName("Node3");

    // 2. Get observer graph instance
    auto& observerGraph = reaction::ObserverGraph::getInstance();

    // 3. Create batch ID
    std::string batchId = "batch_test_001";

    // 4. Register nodes to batch
    observerGraph.registerNodeToBatch(node1, batchId);
    observerGraph.registerNodeToBatch(node2, batchId);
    observerGraph.registerNodeToBatch(node3, batchId);

    // 5. Verify nodes are in batch
    if (!observerGraph.isNodeInBatch(node1, batchId) ||
        !observerGraph.isNodeInBatch(node2, batchId) ||
        !observerGraph.isNodeInBatch(node3, batchId)) {
        return false;
    }

    // 6. Unregister batch
    observerGraph.unregisterBatch(batchId);

    // 7. Verify nodes are no longer in batch
    if (observerGraph.isNodeInBatch(node1, batchId) ||
        observerGraph.isNodeInBatch(node2, batchId) ||
        observerGraph.isNodeInBatch(node3, batchId)) {
        return false;
    }

    // 8. Return success status
    return true;
}

}  // namespace test_reaction
