    int initialCalcValue = calc.get();

    // Update the variable
    var.set(baseValue + increment);

    // Get updated values
    int updatedExprValue = expr.get();
    int updatedCalcValue = calc.get();

    return CreateFactoryResult{
        initialExprValue,
