    // Create observer nodes
    auto direct_observer = std::make_shared<NamedObserverNode>("direct");
    auto transitive_observer = std::make_shared<NamedObserverNode>("transitive");
    auto source_node = std::make_shared<NamedObserverNode>("source");

    // Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // Register nodes
    graph.registerNode(direct_observer);
    graph.registerNode(transitive_observer);
    graph.registerNode(source_node);

    // Set up direct observer relationship
    source_node->addObserver(direct_observer);

    // Set up transitive observer relationship (observer observes another observer)
    direct_observer->addObserver(transitive_observer);

    // Create set to store collected observers
    reaction::NodeSet collected_observers;

    // Collect observers from source node
    graph.collectObservers(source_node, collected_observers);

    // Check results
    bool has_direct = collected_observers.find(direct_observer) != collected_observers.end();
    bool has_transitive = collected_observers.find(transitive_observer) != collected_observers.end();

